import { create } from "zustand";
import type { NewOrderDraft, Order, OrderStatus } from "@/types/order";
import { buildOrderFromDraft, calcSubtotalCents, calcTaxCents, calcTotalCents } from "@/utils/orderMath";
import { createId } from "@/utils/id";
import { supabase } from "@/lib/supabase";
import { pushToGoogleSheet } from "@/lib/sheetsWebhook";

type OrdersState = {
  orders: Order[];
  isLoading: boolean;
  loadOrders: () => Promise<void>;
  createOrder: (draft: NewOrderDraft) => Promise<string>;
  updateCustomer: (id: string, next: Pick<Order, "customerName" | "customerPhone">) => void;
  updateNotes: (id: string, notes: string) => void;
  confirmPaid: (id: string) => Promise<void>;
  setStatus: (id: string, status: Exclude<OrderStatus, "UNPAID">) => Promise<void>;
  addItem: (id: string, item: { name: string; unitPriceCents: number }) => void;
  updateItemQty: (id: string, itemId: string, qty: number) => void;
  removeItem: (id: string, itemId: string) => void;
  deleteOrder: (id: string) => Promise<void>;
  getOrderById: (id: string) => Order | undefined;
};

const TABLE = "orders";
const debouncedSaves = new Map<string, number>();

function recalc(order: Order): Order {
  const subtotalCents = calcSubtotalCents(order.items);
  const taxCents = calcTaxCents(subtotalCents);
  const totalCents = calcTotalCents(subtotalCents, taxCents);
  const updatedAt = new Date().toISOString();
  return { ...order, subtotalCents, taxCents, totalCents, updatedAt };
}

async function upsertOrder(order: Order) {
  const row = { id: order.id, payload: order, updated_at: new Date().toISOString() };
  const { error } = await supabase.from(TABLE).upsert(row);
  if (error) throw error;
}

function scheduleSave(order: Order) {
  const existing = debouncedSaves.get(order.id);
  if (existing) window.clearTimeout(existing);

  const handle = window.setTimeout(() => {
    debouncedSaves.delete(order.id);
    upsertOrder(order)
      .then(() => pushToGoogleSheet("order_updated", order))
      .catch(() => {});
  }, 500);

  debouncedSaves.set(order.id, handle);
}

export const useOrdersStore = create<OrdersState>((set, get) => ({
  orders: [],
  isLoading: false,

  loadOrders: async () => {
    set({ isLoading: true });
    const { data, error } = await supabase.from(TABLE).select("payload,created_at").order("created_at", { ascending: false });
    if (error) {
      set({ isLoading: false });
      throw error;
    }
    const orders = (data || []).map((r: any) => r.payload as Order);
    set({ orders, isLoading: false });
  },

  createOrder: async (draft) => {
    const order = buildOrderFromDraft(draft);
    const createdAt = new Date().toISOString();
    const row = { id: order.id, payload: order, created_at: createdAt, updated_at: createdAt };
    const { error } = await supabase.from(TABLE).insert(row);
    if (error) throw error;
    pushToGoogleSheet("order_created", order).catch(() => {});
    set((state) => ({ orders: [order, ...state.orders] }));
    return order.id;
  },

  updateCustomer: (id, next) => {
    set((state) => {
      const orders = state.orders.map((o) =>
        o.id === id
          ? { ...o, customerName: next.customerName.trim(), customerPhone: next.customerPhone.trim(), updatedAt: new Date().toISOString() }
          : o,
      );
      const updated = orders.find((o) => o.id === id);
      if (updated) scheduleSave(updated);
      return { orders };
    });
  },

  updateNotes: (id, notes) => {
    set((state) => {
      const orders = state.orders.map((o) => (o.id === id ? { ...o, notes: notes.trim(), updatedAt: new Date().toISOString() } : o));
      const updated = orders.find((o) => o.id === id);
      if (updated) scheduleSave(updated);
      return { orders };
    });
  },

  confirmPaid: async (id) => {
    const order = get().orders.find((o) => o.id === id);
    if (!order || order.isPaid) return;

    const paidAt = new Date().toISOString();
    const next: Order = { ...order, isPaid: true, paidAt, status: order.status === "UNPAID" ? "ACCEPTED" : order.status, updatedAt: paidAt };

    await upsertOrder(next);
    pushToGoogleSheet("order_paid", next).catch(() => {});
    set((state) => ({ orders: state.orders.map((o) => (o.id === id ? next : o)) }));
  },

  setStatus: async (id, status) => {
    const order = get().orders.find((o) => o.id === id);
    if (!order || !order.isPaid) return;

    const next: Order = { ...order, status, updatedAt: new Date().toISOString() };
    await upsertOrder(next);
    pushToGoogleSheet("order_status_changed", next).catch(() => {});
    set((state) => ({ orders: state.orders.map((o) => (o.id === id ? next : o)) }));
  },

  addItem: (id, item) => {
    set((state) => {
      const orders = state.orders.map((o) => {
        if (o.id !== id) return o;
        const next: Order = { ...o, items: [...o.items, { id: createId("item"), name: item.name.trim(), qty: 1, unitPriceCents: item.unitPriceCents }] };
        return recalc(next);
      });
      const updated = orders.find((o) => o.id === id);
      if (updated) scheduleSave(updated);
      return { orders };
    });
  },

  updateItemQty: (id, itemId, qty) => {
    set((state) => {
      const orders = state.orders.map((o) => {
        if (o.id !== id) return o;
        const next: Order = { ...o, items: o.items.map((it) => (it.id === itemId ? { ...it, qty } : it)) };
        return recalc(next);
      });
      const updated = orders.find((o) => o.id === id);
      if (updated) scheduleSave(updated);
      return { orders };
    });
  },

  removeItem: (id, itemId) => {
    set((state) => {
      const orders = state.orders.map((o) => {
        if (o.id !== id) return o;
        const next: Order = { ...o, items: o.items.filter((it) => it.id !== itemId) };
        return recalc(next);
      });
      const updated = orders.find((o) => o.id === id);
      if (updated) scheduleSave(updated);
      return { orders };
    });
  },

  deleteOrder: async (id) => {
    const order = get().orders.find((o) => o.id === id);
    const { error } = await supabase.from(TABLE).delete().eq("id", id);
    if (error) throw error;
    if (order) pushToGoogleSheet("order_deleted", order).catch(() => {});
    set((state) => ({ orders: state.orders.filter((o) => o.id !== id) }));
  },

  getOrderById: (id) => get().orders.find((o) => o.id === id),
}));